const ERR_INVALID_PARAM int32 = 1 // Invalid parameters

// Main PDU interface
type Pdu interface {
	idl.Object

	// Retrieve the PDU nameplate information.
	//
	//	@return Nameplate information
	GetNameplate(ctx context.Context) (nameplate.Nameplate, error)

	// Retrieve the PDU metadata.
	//
	//	@return PDU metadata
	GetMetaData(ctx context.Context) (MetaData, error)

	// Retrieve the PDU sensors.
	//
	//	@return PDU sensors
	GetSensors(ctx context.Context) (Sensors, error)

	// Get the sensor logger.
	//
	//	@return Sensor logger reference
	GetSensorLogger(ctx context.Context) (sensorlogger.Logger, error)

	// Get the alerted sensor manager.
	//
	//	@return Alerted sensor manager
	GetAlertedSensorManager(ctx context.Context) (alertedsensormanager.AlertedSensorManager, error)

	// Get the list of sub controllers.
	//
	//	@return List of sub controllers
	GetControllers(ctx context.Context) ([]controller.Controller, error)

	// Get the list of outlets.
	//
	//	@return List of outlets, indexed by their number (0-based)
	GetOutlets(ctx context.Context) ([]outlet.Outlet, error)

	// Get the list of overcurrent protectors.
	//
	//	@return List of OCPs, indexed by their number (0-based)
	GetOverCurrentProtectors(ctx context.Context) ([]overcurrentprotector.OverCurrentProtector, error)

	// Get the list of inlets.
	//
	//	@return List of inlets, indexed by their number (0-based)
	GetInlets(ctx context.Context) ([]inlet.Inlet, error)

	// Returns list of Transfer Switches.
	// This list may be empty.
	GetTransferSwitches(ctx context.Context) ([]transferswitch.TransferSwitch, error)

	// Get the peripheral device manager.
	//
	//	@return Peripheral device manager
	GetPeripheralDeviceManager(ctx context.Context) (peripheraldevicemanager.DeviceManager, error)

	// Get the built-in beeper, if there is any.
	//
	//	@return Beeper interface
	GetBeeper(ctx context.Context) (internalbeeper.InternalBeeper, error)

	// Retrieve the PDU settings.
	//
	//	@return PDU settings
	GetSettings(ctx context.Context) (Settings, error)

	// Retrieve the current load shedding state.
	//
	//	@return true if load shedding is currently enabled
	IsLoadSheddingActive(ctx context.Context) (bool, error)

	// Change the PDU settings.
	//
	//	@param settings  New PDU settings
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	//
	//	@note The Settings structure can be "sparse"; fields missing in the
	//	      JSON representation will remain unchanged.
	SetSettings(ctx context.Context, settings Settings) (int32, error)

	// Enable or disable load shedding.
	//
	//	@param active  true to enable, false to disable load shedding
	SetLoadSheddingActive(ctx context.Context, active bool) error

	// Get all feature ports of this device
	//
	// This returns an entry for all feature ports, no matter whether
	// something is connected or not.
	// A device with n feature ports will return n entries here.
	//
	//	@return List of all Feature Ports
	GetFeaturePorts(ctx context.Context) ([]port.Port, error)

	// Get all sensor ports of this device
	//
	// This returns an entry for all sensor ports, no matter whether
	// something is connected or not.
	// A device with n sensor ports will return n entries here.
	//
	//	@return List of all Sensor Ports
	GetSensorPorts(ctx context.Context) ([]port.Port, error)

	// Get all remote hub ports of this device
	//
	// This returns an entry for all remote hub ports, no matter whether
	// something is connected or not.
	// A device with n remote hub ports will return n entries here.
	//
	//	@return List of all Remote Hub Ports
	GetRemoteHubPorts(ctx context.Context) ([]port.Port, error)

	// Enter RS485 config mode and assign an address to a relay board.
	// @warning This is dangerous! Do not use except for manufacturing.
	//
	//	@param addr     New relay board address
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	EnterRS485ConfigModeAndAssignCtrlBoardAddress(ctx context.Context, addr int32) (int32, error)

	// Enter RS485 config mode and assign an address to a sub controller
	// device with a given device ID.
	// @warning This is dangerous! Do not use except for manufacturing.
	//
	//	@param deviceId Device id of the sub controller
	//	                which is supposed to get the address
	//	@param addr     New relay board address
	//
	//	@return 0 if OK
	//	@return 1 if any parameters are invalid
	EnterRS485ConfigModeAndAssignSCBoardAddress(ctx context.Context, deviceId int32, addr int32) (int32, error)

	// Leave RS485 config mode.
	//
	//	@return 0 if OK
	LeaveRS485ConfigMode(ctx context.Context) (int32, error)

	// Switch all outlets.
	//
	//	@param pstate  New power state for all outlets
	//
	//	@return 0 if OK
	SetAllOutletPowerStates(ctx context.Context, pstate outlet.PowerState) (int32, error)

	// Switch multiple outlets.
	//
	//	@param outletNumbers    List of outlet numbers (0-based)
	//	@param state            New power state for all outlets in list
	//	@param respectSequence  true to switch in defined sequence order
	//
	//	@return 0 if OK
	//	@return 3 if any of the selected outlets is disabled
	SetMultipleOutletPowerStates(ctx context.Context, outletNumbers []int32, state outlet.PowerState, respectSequence bool) (int32, error)

	// Power-cycle all outlets.
	//
	//	@return 0 if OK
	CycleAllOutletPowerStates(ctx context.Context) (int32, error)

	// Power-cycle multiple outlets.
	//
	//	@param outletNumbers    List of outlet numbers (0-based)
	//	@param respectSequence  true to switch in defined sequence order
	//
	//	@return 0 if OK
	//	@return 3 if any of the selected outlets is disabled
	CycleMultipleOutletPowerStates(ctx context.Context, outletNumbers []int32, respectSequence bool) (int32, error)

	// Retrieve PDU statistics.
	//
	//	@return PDU statistics
	GetStatistic(ctx context.Context) (Statistic, error)

	// Retrieve the current outlet sequencing status.
	//
	//	@return Sequencing status
	GetOutletSequenceState(ctx context.Context) (OutletSequenceState, error)

	// Stop a currently running outlet sequence.
	CancelOutletSequence(ctx context.Context) error
}

// PDU orientations
type Orientation int

const (
	PO_NONE       Orientation = iota // No PDU orientation (non-reversible ETO, default)
	PO_BOTTOMFEED                    // Bottom feed PDU orientation (reversible ETO, normal order)
	PO_TOPFEED                       // Top feed PDU orientation (reversible ETO, reversed order)
)

// PDU metadata
type MetaData struct {
	Nameplate               nameplate.Nameplate // Nameplate information
	CtrlBoardSerial         string              // Main controller serial number
	HwRevision              string              // Hardware revision
	FwRevision              string              // Firmware revision
	MacAddress              string              // MAC address
	HasSwitchableOutlets    bool                // true if at least one outlet is switchable
	HasMeteredOutlets       bool                // true if at least one outlet is metered
	HasLatchingOutletRelays bool                // true if at least one outlet has a latching relay
	IsInlineMeter           bool                // true if all inlets have exactly one outlet
	// true if the PDU has one or more LED(s) capable
	// of emitting pulses to measure consumed energy
	IsEnergyPulseSupported bool
	HasDCInlets            bool        // true if at least one inlet is DC
	PduOrientation         Orientation // PDU orientation at boot
}

// PDU sensors
type Sensors struct {
	PowerSupplyStatus []statesensor.StateSensor   // Power supply fault status
	ActivePower       numericsensor.NumericSensor // Active power sensor
	ApparentPower     numericsensor.NumericSensor // Active power sensor
	ActiveEnergy      numericsensor.NumericSensor // Active energy sensor
	ApparentEnergy    numericsensor.NumericSensor // Active energy sensor
}

// PDU statistics
type Statistic struct {
	CbStats         []overcurrentprotector.CircuitBreakerStatistic  // Circuit breaker statistics
	CtrlStats       []controller.CtrlStatistic                      // Sub controller statistics
	OutletStats     []outlet.Statistic                              // Outlet statistics
	PeripheralStats peripheraldevicemanager.DeviceManagerStatistics // Peripheral device statistics
}

// Outlet power state on device startup
type StartupState int

const (
	SS_ON        StartupState = iota // Outlet will be switched on
	SS_OFF                           // Outlet will be switched off
	SS_LASTKNOWN                     // Restore last known power state
)

// PDU settings
type Settings struct {
	Name             string       // User-defined name
	StartupState     StartupState // Default outlet state after applying power to outlets; can be overriden per outlet
	CycleDelay       int32        // Default power-cycle interval in seconds; can be overriden per outlet
	InRushGuardDelay int32        // Minimum delay in milliseconds between switching two outlets on
	// The order in which multiple outlets should be switched.
	// Format: List of outlet numbers (0-based), empty for default.
	// Affects the following functions:
	//   - setAllOutletPowerStates
	//   - cycleAllOutletPowerStates
	//   - setMultipleOutletPowerStates
	//   - cycleMultipleOutletPowerStates
	OutletPowerStateSequence []int32
	PowerOnDelay             int32 // Delay in seconds before restoring outlet states after power is applied to outlets
	LatchingRelays           bool  // If true, relays keep their state during power-cycling
	EnergyPulseEnabled       bool  // Enables energy consumption counting using the PDU's LED(s)
	EnergyPulsesPerKWh       int32 // Ratio between LED pulses and energy consumption
	DemandUpdateInterval     int32 // BCM2 only: Update interval in seconds for demand sensors
	DemandAveragingIntervals int32 // BCM2 only: Average demand sensors over this many update intervals
	// If true, outlets suspected to have caused an OCP to trip are
	// automatically suspended (turned off)
	SuspendTripCauseOutlets bool
}

// Outlet sequencing status
type OutletSequenceState struct {
	SequenceRunning     bool  // true if an outlet sequence is currently running
	NextOutletToSwitch  int32 // Number (0-based) of the next outlet in the sequence
	TimeUntilNextSwitch int32 // Time in milliseconds before the next outlet is switched
	OutletsRemaining    int32 // Number of outlets remaining in the sequence
	// Number of outlets remaining whose switch operation can be canceled
	// (non-cancelable operations won't be affected by canceling the sequence)
	CancelableOutletsRemaining int32
}

// Event: PDU settings have been changed
type SettingsChangedEvent interface {
	userevent.UserEvent
	OldSettings() Settings // Settings before change
	NewSettings() Settings // Settings after change
	isSettingsChangedEvent()
}

// Event: Load shedding mode was enabled or disabled
type LoadSheddingModeChangedEvent interface {
	userevent.UserEvent
	Enabled() bool // Whether load shedding mode is enabled after the change
	isLoadSheddingModeChangedEvent()
}

// Event: Outlet sequencing state has changed
type OutletSequenceStateChangedEvent interface {
	event.Event
	NewState() OutletSequenceState // New sequencing state
	isOutletSequenceStateChangedEvent()
}
